<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <title>Kanban Board</title>
  <style>
    body { font-family: sans-serif; }

    #container {
      display: flex;
      width: 80%;
      margin: 20px auto;
    }

    #col-todo, #col-doing, #col-done {
      flex: 1;
      border: 1px solid #ccc;
      padding: 10px;
      min-height: 300px;
      overflow-y: auto;
    }

    .count {
      font-weight: bold;
      margin-bottom: 5px;
    }

    .card {
      background-color: #f9f9f9;
      border: 1px solid #ccc;
      padding: 10px;
      margin-bottom: 5px;
      cursor: grab;
      user-select: none; /* Prevent text selection during drag */
    }

    .card-del {
      float: right;
      font-weight: bold;
      color: red;
      padding: 2px;
      border: 1px solid red;
      cursor: pointer;
    }

    #new-card, #add-card {
      margin-right: 5px;
    }
  </style>
</head>
<body>
  <h1>Kanban Board</h1>

  <div id="container">
    <div id="col-todo" class="column" draggable="true">
      <span class="count">0</span>
      <div id="new-card">New Card</div>
      <button id="add-card">Add</button>
      <div id="col-todo-cards"></div>
    </div>

    <div id="col-doing" class="column" draggable="true">
      <span class="count">0</span>
      <div id="col-doing-cards"></div>
    </div>

    <div id="col-done" class="column" draggable="true">
      <span class="count">0</span>
      <div id="col-done-cards"></div>
    </div>
  </div>

  <script>
    const columns = {
      todo: document.getElementById('col-todo'),
      doing: document.getElementById('col-doing'),
      done: document.getElementById('col-done')
    };

    let cardData = []; // Store card titles and column IDs

    function updateCardCount(column) {
      const countElement = columns[column].querySelector('.count');
      countElement.textContent = cardData.filter(card => card.column === column).length;
    }

    function addCard(title) {
      if (title.trim() !== '') {
        const newCard = document.createElement('div');
        newCard.classList.add('card');
        newCard.draggable = true;
        newCard.textContent = title;

        // Add delete button
        const delButton = document.createElement('button');
        delButton.classList.add('card-del');
        delButton.textContent = 'Delete';
        newCard.appendChild(delButton);

        // Handle drag and drop
        newCard.addEventListener('dragstart', (e) => {
          e.dataTransfer.setData('text/plain', newCard.id);
        });

        columns[cardData.length % 3].appendChild(newCard);
        cardData.push({ title: title, column: cardData.length % 3 });
        updateCardCount(Object.keys(columns)[cardData.length % 3]); // Update count based on the column index
        document.getElementById('new-card').value = '';
      }
    }

    function dropCard(event) {
      const cardId = event.dataTransfer.getData('text/plain');
      const card = document.getElementById(cardId);
      const column = event.target.closest('.column'); // Find the closest column element

      if (column) {
        column.appendChild(card);
        const index = cardData.findIndex(c => c.id === cardId);
        if (index !== -1) {
          cardData[index].column = columns.indexOf(column);
          updateCardCount(columns.indexOf(column));
        }
      }
    }

    document.getElementById('add-card').addEventListener('click', () => {
      const title = document.getElementById('new-card').value;
      addCard(title);
    });

    document.querySelectorAll('.column').forEach(column => {
      column.addEventListener('dragover', (e) => {
        e.preventDefault();
      });

      column.addEventListener('drop', dropCard);
    });


    // Load from localStorage on page load
    window.onload = () => {
      const storedCards = JSON.parse(localStorage.getItem('kanbanBoard') || '[]');
      storedCards.forEach(card => {
        const cardElement = document.createElement('div');
        cardElement.classList.add('card');
        cardElement.draggable = true;
        cardElement.textContent = card.title;

        // Add delete button
        const delButton = document.createElement('button');
        delButton.classList.add('card-del');
        delButton.textContent = 'Delete';
        cardElement.appendChild(delButton);

        const column = columns[card.column];
        column.appendChild(cardElement);
        cardData.push({ title: card.title, column: card.column });
        updateCardCount(card.column);
      });
    };

    // Save to localStorage on page unload
    window.onbeforeunload = () => {
      localStorage.setItem('kanbanBoard', JSON.stringify(cardData));
    };
  </script>
</body>
</html>
